import React, { useState } from "react";
import ReactDOM from "react-dom/client";
import { BrowserRouter, Route, Routes } from "react-router-dom";
import { createTheme, ThemeProvider } from "@mui/material/styles";
import CssBaseline from "@mui/material/CssBaseline";
import "./index.css";
import Home from "./components/Home";

// IMPORT YOUR CONTEXT PROVIDER HERE TO FIX THE DASHBOARD CRASH
// Adjust this path if your Context file is named or located elsewhere!
import { GeneralContextProvider } from "./context/GeneralContext";

function Root() {
  // 1. Global state for Dark/White theme functionality
  const [darkMode, setDarkMode] = useState(false);

  // 2. Material-UI Theme Definition
  const theme = createTheme({
    palette: {
      mode: darkMode ? "dark" : "light",
      background: {
        default: darkMode ? "#121212" : "#ffffff",
        paper: darkMode ? "#1e1e1e" : "#ffffff",
      },
      text: {
        primary: darkMode ? "#ffffff" : "#000000",
        secondary: darkMode ? "#aaaaaa" : "#666666",
      },
    },
  });

  return (
    <GeneralContextProvider>
      <ThemeProvider theme={theme}>
        {/* Ensures uniform background colors across the whole body tag */}
        <CssBaseline />
        <BrowserRouter>
          <Routes>
            {/* 3. Pass theme controls down to Home */}
            <Route
              path="/*"
              element={<Home darkMode={darkMode} setDarkMode={setDarkMode} />}
            />
          </Routes>
        </BrowserRouter>
      </ThemeProvider>
    </GeneralContextProvider>
  );
}

const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <React.StrictMode>
    <Root />
  </React.StrictMode>,
);
